    fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, sans-serif",
    position: "relative",
    overflow: "hidden"
  },
  card: {
    backgroundColor: "#E0F2F7",
    // Light blue card background from the image
    padding: "50px 40px",
    borderRadius: "20px",
    boxShadow: `0 25px 50px -12px rgba(0, 0, 0, 0.2)`,
    // Adjusted shadow
    width: "100%",
    maxWidth: "420px",
    border: "none",
    // No border as in the image
    position: "relative",
    zIndex: 10,
    animation: "slideUp 0.8s ease-out"
  },
  cardGlow: {
    // Keeping glow but it might not be visible with solid background
    position: "absolute",
    top: 0,
    left: 0,
    right: 0,
    height: "1px",
    background: "linear-gradient(90deg, transparent, #3B82F6, transparent)",
    animation: "glow 3s ease-in-out infinite"
  },
  logo: {
    textAlign: "center",
    marginBottom: "40px",
    animation: "fadeIn 1s ease-out"
  },
  logoText: {
    fontSize: "42px",
    fontWeight: "800",
    color: "#333",
    // Darker text for Flow Track from the image
    margin: "0",
    letterSpacing: "-0.02em"
  },
  tagline: {
    textAlign: "center",
    color: "#666",
    // Darker text for tagline from the image
    fontSize: "14px",
    marginTop: "8px",
    fontWeight: "400",
    letterSpacing: "0.02em"
  },
  title: {
    textAlign: "center",
    marginBottom: "35px",
    fontSize: "28px",
    fontWeight: "700",
    color: "#333",
    // Darker text for Welcome User from the image
    marginTop: "0"
  },
  inputGroup: {
    marginBottom: "25px",
    position: "relative"
  },
  label: {
    display: "block",
    marginBottom: "8px",
    fontSize: "14px",
    fontWeight: "600",
    color: "#333",
    // Darker label text from the image
    transition: "all 0.3s ease"
  },
  inputContainer: {
    position: "relative",
    transition: "all 0.3s ease"
  },
  input: {
    width: "100%",
    padding: "16px 50px 16px 20px",
    borderRadius: "12px",
    border: "1px solid #ccc",
    // Light gray border from the image
    fontSize: "15px",
    color: "#333",
    // Darker text for input from the image
    backgroundColor: "#fff",
    // White background from the image
    transition: "all 0.3s ease",
    boxSizing: "border-box",
    fontFamily: "inherit"
  },
  inputFocus: {
    borderColor: "#2196F3",
    // Blue border on focus
    boxShadow: "0 0 0 3px rgba(33, 150, 243, 0.3)",
    // Blue shadow on focus
    transform: "none" // No transform on focus as in the image
  },
  inputIcon: {
    position: "absolute",
    right: "15px",
    top: "50%",
    transform: "translateY(-50%)",
    color: "#666",
    // Darker icon color from the image
    transition: "all 0.3s ease",
    fontSize: "18px",
    width: "20px",
    height: "20px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center"
  },
  eyeIcon: {
    position: "absolute",
    right: "15px",
    top: "50%",
    transform: "translateY(-50%)",
    color: "#666",
    // Darker icon color
    transition: "all 0.3s ease",
    cursor: "pointer",
    fontSize: "18px",
    background: "none",
    border: "none",
    padding: "5px",
    borderRadius: "4px",
    width: "20px",
    height: "20px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center"
  },
  eyeIconHover: {
    backgroundColor: "rgba(0, 0, 0, 0.05)",
    // Slightly darker background on hover
    color: "#2196F3" // Blue on hover
  },
  button: {
    width: "100%",
    padding: "16px",
    border: "none",
    borderRadius: "12px",
    backgroundColor: "#3F51B5",
    // Solid blue button from the image
    color: "#FFFFFF",
    fontWeight: "600",
    fontSize: "15px",
    cursor: "pointer",
    transition: "all 0.3s ease",
    position: "relative",
    overflow: "hidden",
    boxShadow: "0 4px 15px rgba(63, 81, 181, 0.3)" // Shadow adjusted to button color
  },
  buttonHover: {
    transform: "translateY(-3px)",
    boxShadow: "0 8px 25px rgba(63, 81, 181, 0.4)" // Shadow adjusted to button color
  },
  buttonDisabled: {
    opacity: "0.6",
